var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>성황청</color> 폐쇄지구 어느 폐건물","JPN":"<color=#ffd34c>聖皇庁</color>閉鎖地区のある廃墟","ENG":"<color=#ffd34c>Holy Curia</color> Closed off District, in an abandoned building","TWN":"<color=#ffd34c>聖皇廳</color>封鎖區某個廢棄建築"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"17년 만인가……. 이곳도 오래간만이로군.","JPN":"17年ぶりか……久しいな。","ENG":"It's been a long time since I was last here... What was it? 17 years?","TWN":"時隔17年……好久沒來這裡了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"버넷 경과의 마지막 결투를 벌였던 곳.","JPN":"バーネット卿との最後の決闘の場所。","ENG":"The place where I had my last battle with Sir Burnett.","TWN":"這裡是與伯內特卿展開最後決鬥的地方。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"그래. 이곳 이름이…… <color=#ffd34c>로젠탈</color>이라고 했던가?","JPN":"そう、ここは……<color=#ffd34c>ローゼンタール</color>と言ったか。","ENG":"Yes. What was the name...? <color=#ffd34c>Rosenthal</color>, was it?","TWN":"沒錯，這地方好像是叫<color=#ffd34c>羅森泰</color>？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"학부장님. 미미하지만, 감지기에 신호가 잡히기 시작했습니다.","JPN":"学部長、わずかですが感知器が信号を捉えました。","ENG":"Sir. It's weak, but the detector has started to pick up on a signal.","TWN":"院長，雖然很微弱，但是感應器開始捕捉到訊號了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L11_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"틀림없습니다. 이곳은 과거 균열에 의해 차원 계면이 손상되었던 곳입니다.","JPN":"間違いありません。ここは過去、亀裂によって次元界面が損傷した場所です。","ENG":"I'm positive. This place has been damaged in the past by the rift.","TWN":"絕對沒錯。這裡就是次元裂縫過去因裂縫而受損的地方。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"……아아, 역시 그렇군.","JPN":"……ああ、やはりそうだったか。","ENG":"...Ah, I knew it.","TWN":"……啊，果然如此。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"역시 그날…… 아이들이 사라졌던 건, 결투로 인해 발생한 차원 균열 때문이었나?","JPN":"あの日……子どもたちが消えたのは、決闘による次元亀裂のせいだったのだな。","ENG":"So that day... the children must've disappeared because of the dimensional rift created by the battle.","TWN":"那天……孩子們消失，果真是因為決鬥引起的次元裂縫？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"오보에를 준비하게.","JPN":"オーボエを用意してくれ。","ENG":"Prepare the oboe.","TWN":"準備好雙簧管。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"17년 전, 균열이 발생했던 이곳에서…… 또 한 번 차원 균열을 발생시키는 거야.","JPN":"17年前、亀裂が発生したこの場所で……もう一度、次元の亀裂を発生させるのだ。","ENG":"I am going to create another rift... in the same place where one occurred 17 years ago.","TWN":"17年前，在曾出現裂縫的這個地方……再次製造次元裂縫。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"그리하면 마침내…… 우리가 그토록 찾아 헤매던, 성배에 다다를 수 있을 테니까.","JPN":"そうすればついに……我々が探し求めていた聖杯に辿り着けるだろう。","ENG":"Then finally... I will be able to reach the Holy Grail we've been searching for so long.","TWN":"那麼最終……就可以到達我們苦苦找尋的聖杯。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_QM","text":{"KOREA":"나 참. 누가 그걸 지켜보고 있을 거 같아?","JPN":"ふざけるな。そんなことさせるものか。","ENG":"Blimey. You think we're just gonna stand back and watch?","TWN":"喔？那麼你以為我們會袖手旁觀嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"자네는……?","JPN":"君は……？","ENG":"You're...?","TWN":"你是……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"드디어 따라잡았다. 이 빌어먹을 늙다리!","JPN":"やっと追いついたぞ、このクソジジイ！","ENG":"Finally caught up with you, you old geezer!","TWN":"終於追上了，你這個老不死的！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"이거 우연이로군. 아니, 어쩌면 필연인가.","JPN":"こんな偶然が……いや、必然かもしれないな。","ENG":"What a coincidence. Or should I say it's inevitable?","TWN":"呵呵，這是巧合嗎？還是說，這是必然？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"버넷 경과 마지막 결투를 나눈 곳에서 만난 사람이…… 하필, 자네일 줄이야.","JPN":"バーネット卿との最後の決闘の場で鉢合わせた者が……よりにもよって君だとは。","ENG":"The person I meet where I last fought Sir Burnett... just had to be you.","TWN":"在和伯內特卿進行最後決鬥的地方遇見的人……沒想到，偏偏是你。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"기관이 여기를 어떻게 알고 온 거지?","JPN":"機関はどうやってこの場所がわかったのかね？","ENG":"How did the Institution know where to find me?","TWN":"機關是怎麼知道這裡的？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"아아, 그거 말이야?","JPN":"ああ、知りたいか？","ENG":"Oh, that?","TWN":"啊啊，這個嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"……크악!?","JPN":"……ぐあっ！？","ENG":"...Aargh!","TWN":"……咳？！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L33_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"이, 이…… 쇠말뚝은……!","JPN":"こ、この……杭は……！","ENG":"Th-these... stakes...!","TWN":"這，這……鐵釘是……！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"안뇽~! 또 보네, 고고학부장님?","JPN":"ハロー！　また会えたね、考古学部長さん？","ENG":"Hey there! Good to see you again, Dean of Archeology!","TWN":"你好~！又見面了，考古學教授？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L38_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"그렇군. 학회가 기관과 손을 잡았나?","JPN":"なるほど。学会が機関と手を組んだか。","ENG":"I see. So the Society has joined hands with the Institution?","TWN":"原來如此。學會跟機關聯手了？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"맞아! 이럴 때 아니면, 얘들이랑 언제 손을 잡아보겠어?","JPN":"正解！　こいつらと手を組む機会なんてそうそうないからね。","ENG":"Yup! When else would we join forces like this, right?","TWN":"沒錯！如果不是這時候，也就沒機會和他們聯手了吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"그렇다면 이곳의 위치를 알려준 건 종교학부장이겠군.","JPN":"だとすると、この場所を教えたのは宗教学部長か。","ENG":"Then the one who told you of this place must be the Dean of Religion.","TWN":"那麼把這個位置告訴你們的，是宗教學院院長吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"걱정 마! 고고학부장님한테 쇠꼬챙이를 쏘는 건 영지에 돌아가서 할 테니까!","JPN":"心配しないで！　考古学部長さんに金属ドリルをお見舞いするのは、アタシの領地に戻ってからだから！","ENG":"Don't worry! I'm not gonna shoot skewers into you until you're back at the estate!","TWN":"別擔心！向考古學教授你射鐵釘，我會等回到領地後再做！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"어머니의 보살핌 아래에 우리는 곧 하나가 될 지니.","JPN":"母の腕の中で、我々はもうじき一つになる。","ENG":"Under Mother's care, we will soon become one.","TWN":"在母親的關懷下，我們即將合而為一。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"모두 죽음을 두려워하지…….","JPN":"皆、死を恐れる……","ENG":"Fear not death, every–","TWN":"大家不要懼怕死亡……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"신자에게 죽음를 강요하는 신이라니. 이단이로군요.","JPN":"信徒に死を強要する神ですか。異端ですね。","ENG":"A god that forces its followers to end their own lives. It is heresy, I say.","TWN":"竟是強迫信徒死亡的神，果然是異端。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이쪽 사교도들은 자해하지 못하도록 제가 무력화시키겠습니다!","JPN":"こちらの邪教徒たちは自害できないよう、私が無力化させます！","ENG":"I will stop the cultists here from inflicting self-harm!","TWN":"我會採取失效措施，不讓這邊的邪教徒自殘！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이 틈에 어서……!","JPN":"その間に早く……！","ENG":"Now is the time...!","TWN":"趁這個機會，盡快……！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"좋아, 부탁한다고. 종이 수녀!","JPN":"ああ、頼んだぞ、ペーパーシスター！","ENG":"All right! Thanks, paper nun!","TWN":"好，拜託你了，紙修女！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"하, 학부장님, 어서 피해야 합니다.","JPN":"が、学部長。早く逃げなければなりません。","ENG":"S-sir, you must get out of here.","TWN":"部，院長，你還是盡快逃走吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L14_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"지금은 <color=#ffd34c>호수의 기사</color>의 도움을 받을 수도 없습니다.","JPN":"今は<color=#ffd34c>湖の騎士</color>に助けてもらうことはできません。","ENG":"We can't receive help from the <color=#ffd34c>Knight of the Lake</color> right now.","TWN":"你現在無法得到<color=#ffd34c>湖水騎士</color>的幫助。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"일단, 물러나시고. 다음을 기약하는 것이…….","JPN":"ひとまずここは退き、次の機会を……","ENG":"It's best to retreat and find another opportunity...","TWN":"先撤退，等以後再……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"……아니.","JPN":"……いや。","ENG":"...No.","TWN":"……不。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"여기까지 와서 멈출 수는 없네.","JPN":"ここまで来て止めるわけにはいかない。","ENG":"I can't stop when I'm this close.","TWN":"都到這裡了，我不能停手。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"오보에의 조율이 끝날 때까지 자네들이 시간을 벌어주게나.","JPN":"オーボエの調律が終わるまで、時間を稼いでくれ。","ENG":"Buy me some time until I'm done tuning the oboe.","TWN":"在結束雙簧管的調音之前，請你們為我爭取時間。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"학부장님!","JPN":"学部長！","ENG":"Sir!","TWN":"院長！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"말하지 않았나? 나는 지금 신탁을 수행 중이야.","JPN":"聞いてなかったか？　私は今神託を遂行している。","ENG":"Didn't I tell you? I am following the prophecy.","TWN":"不是說了嗎？我正在履行神喻。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"그러니 저들도…… 흘러가는 운명을 돌이킬 수는 없을 걸세.","JPN":"だから彼らも……運命の流れに逆らうことはできないだろう。","ENG":"And they too... cannot turn the tides of fate.","TWN":"所以他們……也無法挽回流逝的命運。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나 참. 신탁이라고?","JPN":"は！　神託だと？","ENG":"Blimey, a prophecy?","TWN":"真是的，神喻？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"신탁이 아니라 노망이겠지, 이 미친 노친네야!","JPN":"神託がなんだってんだ、イカれジジイ！","ENG":"I think you're more senile than you look!","TWN":"我看你是老糊塗吧，你這個瘋老頭！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"각오하라고! 깜빵에서 기어 나온 걸 후회하게 만들어 줄 테니까!","JPN":"覚悟しろよ、牢獄から出たことを後悔させてやるからな！","ENG":"Just you wait! I'll make you regret crawling out of your cell!","TWN":"做好覺悟吧！我會讓你後悔從監牢裡爬出來的！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};